task RW_011 {
    require cap(relay1)
    require cap(water_sensor)

    set relay1 = 1
    wait 2000ms
    read relay1
    if (relay1 == 1) {
        halt
    } else {
        retry 3 times {
            set relay1 = 1
            wait 2000ms
            read relay1
            if (relay1 == 1) {
                halt
            }
        }
    }
}

